#include<bits/stdc++.h>
using namespace std;
long long n,m,a[100010],b[100010],h[100010],ans[100010],ans1[100010],c[100010];
struct query
{
    long long x,y,z,f,id;
    bool operator<=(const query&b)const
    {
        return make_pair(y,z)<=make_pair(b.y,b.z);
    }
};
vector<query> v,w;
long long lowbit(long long x)
{
    return x&-x;
}
long long sum[100010];
void add(long long x,long long v)
{
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
long long getsum(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
void cdq(long long l,long long r)
{
    if(l+1>=r)
    {
        return;
    }
    int mid=(l+r)>>1,i=l,j=mid,cnt=0;
    cdq(l,mid);
    cdq(mid,r);
    w.clear();
    while(i<mid||j<r)
    {
        if(i<mid&&(j==r||v[i]<=v[j]))
        {
            w.push_back(v[i]);
            if(!v[i].f)
            {
                add(v[i].z+1,1);
                cnt++;
            }
            i++;
        }
        else
        {
            w.push_back(v[j]);
            if(v[j].f)
            {
                ans[v[j].id]+=v[j].f*getsum(v[j].z+1);
                ans1[v[j].id]+=v[j].f*cnt;
            }
            j++;
        }
    }
    for(int i=l;i<mid;i++)
    {
        if(!v[i].f)
        {
            add(v[i].z+1,-1);
        }
    }
    for(int i=l;i<r;i++)
    {
        v[i]=w[i-l];
    }
}
bool cmp(query a,query b)
{
    if(tuple(a.x,a.y,a.z)==tuple(b.x,b.y,b.z))
    {
        return a.id<b.id;
    }
    return tuple(a.x,a.y,a.z)<tuple(b.x,b.y,b.z);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        b[i]=a[i];
    }
    sort(b+1,b+1+n);
    for(int i=1;i<=n;i++)
    {
        a[i]=lower_bound(b+1,b+1+n,a[i])-b;
        int pre=h[a[i]];
        h[a[i]]=i;
        v.push_back({i,a[i],pre,0,0});
    }
    for(int i=1;i<=m;i++)
    {
        int l,r,A,B;
        scanf("%d%d%d%d",&l,&r,&A,&B);
        A=lower_bound(b+1,b+1+n,A)-b;
        B=upper_bound(b+1,b+1+n,B)-b-1;
        v.push_back({r,B,l-1,1,i});
        v.push_back({l-1,A-1,l-1,1,i});
        v.push_back({l-1,B,l-1,-1,i});
        v.push_back({r,A-1,l-1,-1,i});
    }
    sort(v.begin(),v.end(),cmp);
    cdq(0,v.size());
    for(int i=1;i<=m;i++)
    {
        printf("%d %d\n",ans1[i],ans[i]);
    }
    return 0;
}
